  ('promotion-7c9828ae-moex-00075', 'promotion-7c9828ae', 'promotion-7c9828ae-moex-112-3082b5f1', 'sub-promotion-7c9828ae-04', NULL, 'single_choice', '依行政訴訟法規定，關於訴訟標的對於共同訴訟之各人，必須合一確定者，下列敘述何者錯誤？', '["他造對於共同訴訟人中之一人之行為，其效力及於全體", "共同訴訟人中之一人，生有訴訟當然停止之原因者，其效力及於全體", "共同訴訟人中之一人之行為有利益於共同訴訟人者，其效力及於全體", "共同訴訟人中之一人所為不利益於共同訴訟人之行為，其效力僅及於該人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "108", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會工作"}'::jsonb, NULL),
  ('promotion-7c9828ae-moex-00076', 'promotion-7c9828ae', 'promotion-7c9828ae-moex-112-3082b5f1', 'sub-promotion-7c9828ae-04', NULL, 'single_choice', '下列何者為確認訴訟之類型？', '["確認行政處分不當之訴", "確認行政處分有無誤寫誤算等顯然錯誤之訴", "確認公法上事實關係存在或不存在之訴", "確認行政處分違法之訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "108", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會工作"}'::jsonb, NULL),
  ('promotion-7c9828ae-moex-00077', 'promotion-7c9828ae', 'promotion-7c9828ae-moex-112-3082b5f1', 'sub-promotion-7c9828ae-04', NULL, 'single_choice', '關於國家賠償，下列敘述何者錯誤？', '["公共設施包括非由國家設置，但事實上由其管理且直接供公共使用之設施", "公共設施委託民間團體管理時，因管理欠缺致人民身體受損害者，國家應負損害賠償責任", "國家賠償請求權，自損害發生時起，因2年間不行使而消滅", "賠償義務機關得於一定金額限度內，與請求權人逕行協議決定賠償金額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "108", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會工作"}'::jsonb, NULL),
  ('promotion-7c9828ae-moex-00078', 'promotion-7c9828ae', 'promotion-7c9828ae-moex-112-3082b5f1', 'sub-promotion-7c9828ae-04', NULL, 'single_choice', '人民因執行機關依法實施即時強制，致其財產遭受特別犧牲，得採行何種請求權？', '["請求國家賠償", "請求損失補償", "請求回復原狀", "請求撤銷原強制行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "108", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會工作"}'::jsonb, NULL),
  ('promotion-7c9828ae-moex-00079', 'promotion-7c9828ae', 'promotion-7c9828ae-moex-110-64a61a4d', 'sub-promotion-7c9828ae-01', NULL, 'essay', '中央政府自民國107 年開始推動「強化社會安全網輔導團計畫」，主要在
因應近年來的家庭變遷導致的家庭脆弱性功能之問題，該計畫的策略一
在臺灣各縣市普設 154處的社會福利服務中心，增進服務的可近性，也
配置許多社工人力來推動該項計畫，強調「以家庭為中心、以社區為基
礎」的服務模式，由縣市政府規劃與構築一個跨體系的社區協力網絡，
來支持居住在社區中的兒童、少年、身心障礙者、老人。請提出至少兩
種跨網絡合作的模式來說明該計畫可以推動的方向為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "0858e4aa6d0a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作實務", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會工作"}'::jsonb, NULL),
  ('promotion-7c9828ae-moex-00080', 'promotion-7c9828ae', 'promotion-7c9828ae-moex-110-64a61a4d', 'sub-promotion-7c9828ae-01', NULL, 'essay', '近年來，臺灣的離婚率居高不下，衝擊著家庭的穩定性，未成年子女生
活於單親家庭的機率增高，他們的生活適應問題引起注意。假設你的單
位希望你能找出改善單親家庭子女的社會適應問題的有效介入方法，請
你就兩種團體之介入的策略進行成效評估的比較。策略 A為增進社會技
巧的社會性團體，策略 B 是促進自我肯定的治療性團體。請依據不同策
略設計各 6次的團體活動，並提出你比較此兩個團體的成效之評估設計
為何？提示：評估設計應以量化研究為主，注意成員的召募及成效的測
量。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "0858e4aa6d0a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作實務", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會工作"}'::jsonb, NULL),
  ('promotion-7c9828ae-moex-00081', 'promotion-7c9828ae', 'promotion-7c9828ae-moex-110-64a61a4d', 'sub-promotion-7c9828ae-01', NULL, 'essay', '隨著家庭暴力防治制度的建立，受暴的受害人得以向外尋求協助，得到
正式的支援以爭取自己的人身安全。在社會工作的領域中，一直有學者
主張協助家暴受害人的社會工作者應盡可能採取女性主義的觀點作為
主要的工作取向。請試說明女性主義觀點在解釋家庭暴力發生的原因和
介入方法兩方面的說法為何？並請試評論從事保護性的社會工作者採
取此工作取向的優缺點。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "0858e4aa6d0a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作實務", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會工作"}'::jsonb, NULL),
  ('promotion-7c9828ae-moex-00082', 'promotion-7c9828ae', 'promotion-7c9828ae-moex-110-64a61a4d', 'sub-promotion-7c9828ae-01', NULL, 'essay', '由於社會工作者所服務的對象所處的生活情境相當複雜，以致社工在進
行介入決策時經常面臨「倫理兩難」（ethicaldilemmas）的衝突困境，不
是沒有找到合適的問題解決方案，就是沒有一個建議的方案令人滿意。
但是，社工最後還是得作決定。請就下列案例進行倫理兩難的討論。李
老先生今年 70歲，是個獨居老人，平時以拾荒為生，最近因為中風路倒
而住進醫院，經醫生初判應有初期失智症狀，不宜獨居，但李老先生堅
持返家自行照顧，比較舒服自在。此時，社會工作者面臨什麼樣的倫理
兩難情境？提示：應提出產生兩難的倫理原則，最後請提出合適的倫理
抉擇及處理的方向。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "0858e4aa6d0a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作實務", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會工作"}'::jsonb, NULL),
  ('promotion-7c9828ae-moex-00083', 'promotion-7c9828ae', 'promotion-7c9828ae-moex-110-a62ebd66', 'sub-promotion-7c9828ae-02', NULL, 'essay', '欲透過觀察母群體一小部分，正確推斷出母群體整體特性，機率抽樣是
較佳的抽樣方式。試述機率抽樣的定義，並舉出4 種機率抽樣的類型說
明之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:57+00:00", "source_pdf_sha1": "ced6e7471bf5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "108", "s": "0804", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作研究方法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "社會工作"}'::jsonb, NULL)
